const data = $input.first().json;
const message = data.message || data.body?.message || '';
const msg = message.toLowerCase();
let intent = 'rag';
if (['feedback', 'review', 'relire', 'corriger', 'mon texte', 'my text', 'evaluate'].some(k => msg.includes(k))) {
  intent = 'writing_coach';
} else if (['deadline', 'milestone', 'avancement', 'retard', 'progress', 'on track', 'due'].some(k => msg.includes(k))) {
  intent = 'progress_tracker';
}
return [{
  json: {
    message: message,
    student_id: data.student_id,
    session_id: data.session_id,
    history: data.history || [],
    intent: intent
  }
}];

const triggerData = $input.first().json;
let milestonesData = $input.all()[0]?.json;
// Handle different data formats
let milestones = [];
if (Array.isArray(milestonesData)) {
  milestones = milestonesData;
} else if (milestonesData && typeof milestonesData === 'object') {
  // Maybe wrapped in a property like milestones: [...]
  milestones = milestonesData.milestones || milestonesData.data || [milestonesData];
}
const completed = milestones.filter(m => m.completed);
const pending = milestones.filter(m => !m.completed);
const today = new Date().toISOString().split('T')[0];
const overdue = pending.filter(m => m.due_date && m.due_date < today);
const context = `Student milestones as of today (${today}):
Completed (${completed.length}): ${completed.map(m => m.title).join(', ') || 'none'}
Pending (${pending.length}): ${pending.map(m => `${m.title} (due: ${m.due_date})`).join(', ') || 'none'}
Overdue (${overdue.length}): ${overdue.map(m => m.title).join(', ') || 'none'}`;
return [{ json: { context, message: triggerData.message, student_id: triggerData.student_id, session_id: triggerData.session_id } }];

const responseData = $input.first().json;
const content = responseData.choices?.[0]?.message?.content || "I couldn't get a response.";
return [{ json: { 
  response: content, 
  agent_used: 'progress_tracker', 
  student_id: responseData.student_id, 
  session_id: responseData.session_id 
} }];

const data = $input.first().json;
const chunks = data.chunks ? data.chunks.join('\n\n---\n\n') : '';
const history = data.history || [];
const historyText = history.map(m => `${m.role}: ${m.content}`).join('\n');
const systemPrompt = `You are PFE Coach, an academic advisor helping a university student complete their final-year project.
Your role is to GUIDE, not to do the work for the student.
Use the provided context to answer the student's question clearly and concisely.
If the answer is not in the context, say so honestly.
Never write report sections on behalf of the student. Explain concepts, suggest approaches, and ask guiding questions.
Always respond in the same language the student used (French or English).
Context:
${chunks}`;
return [{
  json: {
    systemPrompt,
    historyText,
    message: data.message,
    student_id: data.student_id,
    session_id: data.session_id
  }
}];

const data = $input.first().json;
const content = data.choices?.[0]?.message?.content || 'No response';
return [{
  json: {
    response: content,
    agent_used: 'rag'
  }
}];

const msg = $input.first().json.message.toLowerCase();
const isWriteRequest = ['write for me', 'écris pour moi', 'write my', 'rédige', 'complete this', 'finish this'].some(k => msg.includes(k));
return [{ json: { ...$input.first().json, isWriteRequest } }];

const content = $input.first().json.choices[0].message.content;
let feedback;
try {
  feedback = JSON.parse(content);
} catch (e) {
  feedback = { overall: content, issues: [], strengths: [], next_step: "Unable to parse feedback" };
}

const response = `Overall: ${feedback.overall}\n\nIssues:\n${feedback.issues.map(i => `- [${i.type.toUpperCase()}] ${i.description} → ${i.suggestion}`).join('\n')}\n\nStrengths:\n${feedback.strengths.map(s => '- ' + s).join('\n')}\n\nNext Step: ${feedback.next_step}`;

return [{ json: { response, agent_used: 'writing_coach', student_id:$('Webhook').first().json.body.student_id , session_id:  $('Webhook').first().json.body.session_id} }];

const data = $input.first().json;
const body = {
  model: "llama-3.1-8b-instant",
  temperature: 0.3,
  messages: [
    { role: "system", content: String(data.systemPrompt || "") },
    { role: "user", content: String(data.message || "") }
  ]
};
return [{ json: body }];

const context = $input.first().json.context;
const userMessage = $input.first().json.message || "What is my progress?";
const studentId = $input.first().json.student_id;
const sessionId = $input.first().json.session_id;
const messages = [
  {
    role: "system",
    content: "You are a progress tracker for university final-year projects. Use ONLY the provided milestone data to answer the student's questions. Never invent deadlines or milestones. If you need information not in the context, say so. Provide encouraging, actionable guidance. Respond in the same language the student used.\n\nContext:\n" + context
  },
  { 
    role: "user", 
    content: userMessage 
  }
];
const body = {
  model: "llama-3.1-8b-instant",
  temperature: 0.3,
  messages: messages
};
return [{ json: { body: JSON.stringify(body), student_id: studentId, session_id: sessionId } }];

const context = $input.first().json.context || "";
const userMessage = $input.first().json.message || "Please review my writing";
const studentId = $input.first().json.student_id;
const sessionId = $input.first().json.session_id;
const messages = [
  {
    role: "system", 
    content: "You are a writing coach for university final-year projects. Help students improve their academic writing. Provide specific, constructive feedback. If you don't have enough context, ask for the text to review.\n\nContext: " + context
  },
  { 
    role: "user", 
    content: userMessage 
  }
];
const body = {
  model: "llama-3.1-8b-instant",
  temperature: 0.3,
  messages: messages
};
return [{ json: { body: JSON.stringify(body), student_id: studentId, session_id: sessionId } }];
